import { useState, useCallback, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "@/contexts/AuthContext";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { toast } from "sonner";
import { motion } from "framer-motion";
import axios from "axios";
import {
  Upload, ScanEye, Loader2, Image, Film, X, ArrowRight, Clock
} from "lucide-react";

const API = `${process.env.REACT_APP_BACKEND_URL}/api`;

export default function DashboardPage() {
  const { token } = useAuth();
  const navigate = useNavigate();
  const [dragging, setDragging] = useState(false);
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [recentAnalyses, setRecentAnalyses] = useState([]);
  const [loadingRecent, setLoadingRecent] = useState(true);

  const fetchRecent = useCallback(async () => {
    try {
      const res = await axios.get(`${API}/analyses`, {
        headers: { authorization: `Bearer ${token}` }
      });
      setRecentAnalyses(res.data.slice(0, 6));
    } catch (err) {
      console.error("Failed to fetch analyses");
    }
    setLoadingRecent(false);
  }, [token]);

  useEffect(() => {
    fetchRecent();
  }, [fetchRecent]);

  const handleFile = (f) => {
    if (!f) return;
    const validTypes = ['image/jpeg', 'image/png', 'image/webp', 'video/mp4', 'video/quicktime', 'video/webm'];
    if (!validTypes.includes(f.type)) {
      toast.error("Unsupported file type. Use JPEG, PNG, WebP, or MP4.");
      return;
    }
    if (f.size > 10 * 1024 * 1024) {
      toast.error("File too large. Max 10MB.");
      return;
    }
    setFile(f);
    const url = URL.createObjectURL(f);
    setPreview(url);
  };

  const onDrop = useCallback((e) => {
    e.preventDefault();
    setDragging(false);
    const f = e.dataTransfer.files[0];
    handleFile(f);
  }, []);

  const onDragOver = (e) => {
    e.preventDefault();
    setDragging(true);
  };

  const onDragLeave = () => setDragging(false);

  const handleAnalyze = async () => {
    if (!file) return;
    setAnalyzing(true);
    try {
      const formData = new FormData();
      formData.append("file", file);
      formData.append("authorization", `Bearer ${token}`);

      const res = await axios.post(`${API}/analyze`, formData, {
        headers: { "Content-Type": "multipart/form-data" },
        timeout: 60000,
      });

      toast.success("Analysis complete!");
      navigate(`/result/${res.data.id}`);
    } catch (err) {
      toast.error(err.response?.data?.detail || "Analysis failed. Please try again.");
    }
    setAnalyzing(false);
  };

  const clearFile = () => {
    setFile(null);
    setPreview(null);
  };

  const isVideo = file?.type?.startsWith("video/");

  return (
    <div className="min-h-screen pt-24 pb-16 px-4" data-testid="dashboard-page">
      <div className="max-w-5xl mx-auto">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="mb-10"
        >
          <h1 className="text-3xl sm:text-4xl font-black tracking-tight mb-2">
            Analyze Media
          </h1>
          <p className="text-muted-foreground">
            Upload an image or video to detect if it's AI-generated or authentic.
          </p>
        </motion.div>

        {/* Upload Zone */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.1 }}
        >
          {!file ? (
            <div
              onDrop={onDrop}
              onDragOver={onDragOver}
              onDragLeave={onDragLeave}
              className={`relative rounded-sm border-2 border-dashed p-16 text-center cursor-pointer transition-all duration-300 ${
                dragging
                  ? "border-[hsl(var(--brand-real))] bg-[hsl(var(--brand-real)/0.05)]"
                  : "border-border hover:border-muted-foreground/50"
              }`}
              onClick={() => document.getElementById("file-input").click()}
              data-testid="upload-dropzone"
            >
              {/* Scanning animation */}
              {dragging && (
                <div className="absolute inset-0 overflow-hidden rounded-sm">
                  <div className="absolute inset-x-0 h-1 bg-gradient-to-r from-transparent via-[hsl(var(--brand-real))] to-transparent animate-scan-line" />
                </div>
              )}

              <div className="flex flex-col items-center gap-4">
                <div className="w-16 h-16 rounded-sm bg-secondary flex items-center justify-center">
                  <Upload className="w-8 h-8 text-muted-foreground" />
                </div>
                <div>
                  <p className="font-medium mb-1">Drop your file here or click to browse</p>
                  <p className="text-sm text-muted-foreground">
                    Supports JPEG, PNG, WebP, MP4 — Max 10MB
                  </p>
                </div>
              </div>

              <input
                id="file-input"
                type="file"
                accept="image/jpeg,image/png,image/webp,video/mp4,video/quicktime,video/webm"
                onChange={(e) => handleFile(e.target.files[0])}
                className="hidden"
                data-testid="file-input"
              />
            </div>
          ) : (
            <Card className="rounded-sm overflow-hidden">
              <CardContent className="p-0">
                <div className="flex flex-col md:flex-row">
                  {/* Preview */}
                  <div className="relative md:w-1/2 bg-secondary/30 flex items-center justify-center min-h-[300px]">
                    {isVideo ? (
                      <video src={preview} className="max-h-[400px] w-full object-contain" controls data-testid="video-preview" />
                    ) : (
                      <img src={preview} alt="Preview" className="max-h-[400px] w-full object-contain" data-testid="image-preview" />
                    )}
                    <Button
                      variant="ghost"
                      size="icon"
                      className="absolute top-3 right-3 rounded-sm bg-background/80 backdrop-blur-sm"
                      onClick={clearFile}
                      data-testid="clear-file-button"
                    >
                      <X className="w-4 h-4" />
                    </Button>
                  </div>

                  {/* Info & Analyze */}
                  <div className="md:w-1/2 p-8 flex flex-col justify-center">
                    <div className="flex items-center gap-3 mb-6">
                      {isVideo ? (
                        <Film className="w-5 h-5 text-muted-foreground" />
                      ) : (
                        <Image className="w-5 h-5 text-muted-foreground" />
                      )}
                      <div>
                        <p className="font-medium text-sm truncate max-w-[250px]">{file.name}</p>
                        <p className="text-xs text-muted-foreground">
                          {(file.size / 1024 / 1024).toFixed(2)} MB — {file.type}
                        </p>
                      </div>
                    </div>

                    <div className="space-y-3 mb-8">
                      <div className="flex items-center gap-2 text-sm text-muted-foreground">
                        <ScanEye className="w-4 h-4" />
                        <span>6-point analysis: Texture, Lighting, Faces, Background, Edges, Metadata</span>
                      </div>
                    </div>

                    <Button
                      onClick={handleAnalyze}
                      disabled={analyzing}
                      className="rounded-sm gap-2 h-11 active:scale-95 transition-all"
                      data-testid="analyze-button"
                    >
                      {analyzing ? (
                        <>
                          <Loader2 className="w-4 h-4 animate-spin" />
                          Analyzing...
                        </>
                      ) : (
                        <>
                          <ScanEye className="w-4 h-4" />
                          Analyze Now
                        </>
                      )}
                    </Button>

                    {analyzing && (
                      <div className="mt-4 p-3 rounded-sm bg-secondary/50 border">
                        <div className="flex items-center gap-2 text-sm text-muted-foreground">
                          <div className="w-2 h-2 rounded-full bg-[hsl(var(--brand-real))] animate-pulse" />
                          Processing with GPT-5.2 Vision...
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              </CardContent>
            </Card>
          )}
        </motion.div>

        {/* Recent Analyses */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.2 }}
          className="mt-16"
        >
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-xl font-bold tracking-tight">Recent Analyses</h2>
            {recentAnalyses.length > 0 && (
              <Button
                variant="ghost"
                size="sm"
                onClick={() => navigate("/history")}
                className="rounded-sm gap-1"
                data-testid="view-all-history-button"
              >
                View All <ArrowRight className="w-3 h-3" />
              </Button>
            )}
          </div>

          {loadingRecent ? (
            <div className="flex items-center justify-center py-12">
              <Loader2 className="w-6 h-6 animate-spin text-muted-foreground" />
            </div>
          ) : recentAnalyses.length === 0 ? (
            <Card className="rounded-sm">
              <CardContent className="py-12 text-center">
                <Clock className="w-8 h-8 text-muted-foreground mx-auto mb-3" />
                <p className="text-muted-foreground">No analyses yet. Upload your first file above!</p>
              </CardContent>
            </Card>
          ) : (
            <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {recentAnalyses.map((a) => (
                <Card
                  key={a.id}
                  className="rounded-sm cursor-pointer hover:shadow-md transition-all duration-200 hover:-translate-y-0.5 overflow-hidden"
                  onClick={() => navigate(`/result/${a.id}`)}
                  data-testid={`analysis-card-${a.id}`}
                >
                  {/* Thumbnail */}
                  {a.file_preview && (
                    <div className="h-32 bg-secondary/30 overflow-hidden">
                      <img
                        src={a.file_preview}
                        alt={a.original_filename}
                        className="w-full h-full object-cover"
                      />
                    </div>
                  )}
                  <CardContent className="p-4">
                    <div className="flex items-center justify-between mb-2">
                      <p className="text-sm font-medium truncate max-w-[150px]">{a.original_filename}</p>
                      <Badge
                        className={`rounded-sm text-xs ${
                          a.verdict === "Likely Real"
                            ? "bg-[hsl(var(--brand-real)/0.1)] text-[hsl(var(--brand-real))] border-[hsl(var(--brand-real)/0.2)]"
                            : "bg-[hsl(var(--brand-fake)/0.1)] text-[hsl(var(--brand-fake))] border-[hsl(var(--brand-fake)/0.2)]"
                        }`}
                        data-testid={`verdict-badge-${a.id}`}
                      >
                        {a.verdict}
                      </Badge>
                    </div>
                    <div className="flex items-center justify-between">
                      <span className="font-mono-data text-xs text-muted-foreground">
                        {new Date(a.created_at).toLocaleDateString()}
                      </span>
                      <span className="font-mono-data text-sm font-medium">
                        {a.confidence_score.toFixed(1)}%
                      </span>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
        </motion.div>
      </div>
    </div>
  );
}
